+    #[test]
+    fn test_prepare_select_star_from_attached_schema_uses_attached_column_names_when_main_matches()
+    {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE t (main_only INTEGER);").unwrap();
+        conn.execute("ATTACH DATABASE ':memory:' AS aux;").unwrap();
+        conn.execute("CREATE TABLE aux.t (aux_id INTEGER, aux_value TEXT);")
+            .unwrap();
+
+        let stmt = conn.prepare("SELECT * FROM aux.t;").unwrap();
+        assert_eq!(stmt.column_count(), 2);
+        assert_eq!(
+            stmt.column_names(),
+            &["aux_id".to_owned(), "aux_value".to_owned()]
+        );
+    }
