+    #[test]
+    fn test_create_table_as_select_star_from_attached_schema_uses_attached_column_names_when_main_matches()
+     {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE t (main_only INTEGER);").unwrap();
+        conn.execute("ATTACH DATABASE ':memory:' AS aux;").unwrap();
+        conn.execute("CREATE TABLE aux.t (aux_id INTEGER, aux_value TEXT);")
+            .unwrap();
+
+        conn.execute("CREATE TABLE copy AS SELECT * FROM aux.t WHERE 0;")
+            .unwrap();
+
+        let pragma_rows = conn.query("PRAGMA table_info(copy);").unwrap();
+        let column_names: Vec<String> = pragma_rows
+            .iter()
+            .map(|row| match &row.values()[1] {
+                SqliteValue::Text(name) => name.to_string(),
+                other => panic!("unexpected PRAGMA table_info name column: {other:?}"),
+            })
+            .collect();
+        assert_eq!(
+            column_names,
+            vec!["aux_id".to_owned(), "aux_value".to_owned()]
+        );
+    }
